/**
 * Canonical snippet selection rule: return all user-specified examples, falling back to
 * the first autogenerated example only when no user-specified examples exist.
 *
 * Mirrors the regular-IR logic that TS-v1 and Python-v1 already apply natively. Without
 * this filter, generators consuming the dynamic IR upload N+M snippet rows per endpoint
 * to FDR (one per user example plus one per autogenerated example), which surface
 * non-deterministically through the /snippets API.
 *
 * The `isUserSpecified` field is set by the dynamic IR converter (CLI ≥ 5.10.x). Older
 * `@fern-fern/ir-sdk` typings don't expose it, so we widen at the boundary; runtime data
 * carries the flag whenever the CLI is at the version that produced it.
 */
export function selectExamplesForSnippets<T>(examples: readonly T[] | undefined): T[] {
    if (examples == null || examples.length === 0) {
        return [];
    }
    const tagged = examples as readonly (T & { isUserSpecified?: boolean })[];
    const userExamples = tagged.filter((example) => example.isUserSpecified === true);
    if (userExamples.length > 0) {
        return userExamples;
    }
    return tagged.filter((example) => example.isUserSpecified !== true).slice(0, 1);
}
